package edu.rice.comp322.boruvka.parallel;

import edu.rice.comp322.boruvka.Component;
import edu.rice.comp322.boruvka.Edge;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.locks.ReentrantLock;

/**
 * This class may be modified.
 *
 * @author <a href="http://shams.web.rice.edu/">Shams Imam</a> (shams@rice.edu)
 */
public final class ParComponent extends Component<ParComponent> {

    public final int nodeId;
    public List<Edge<ParComponent>> pq = new ArrayList<>();
    public double totalWeight = 0;
    public long totalEdges = 0;
    public volatile boolean isDead = false;
    private final ReentrantLock lock = new ReentrantLock();


    protected ParComponent(final int nodeId) {
        super();
        this.nodeId = nodeId;
    }

    @Override
    public int nodeId() {
        return nodeId;
    }

    @Override
    public double totalWeight() {
        return totalWeight;
    }

    @Override
    public long totalEdges() {
        return totalEdges;
    }

    /**
     * insert edge in weight order.
     */
    public void addEdge(final Edge<ParComponent> e) {
        lock.lock();
        try {
            int i = 0;
            while (i < pq.size()) {
                if (e.weight() < pq.get(i++).weight()) {
                    i--;
                    break;
                }
            }
            pq.add(i, e);
        } finally {
            lock.unlock();
        }
    }

    /**
     * Get the edge with minimum weight from the sorted list pq.
     */
    public Edge<ParComponent> getMinEdge() {
        lock.lock();
        try {
            return getMinEdgeLocked();
        } finally {
            lock.unlock();
        }
    }

    /**
     * Merge two components together, connected by an edge with weight edgeWeight.
     */
    public void merge(final ParComponent other, final double edgeWeight) {
        mergeLocked(other, edgeWeight);
    }

    public void lock() {
        lock.lock();
    }

    public void unlock() {
        lock.unlock();
    }

    public Edge<ParComponent> getMinEdgeLocked() {
        while (!pq.isEmpty()) {
            final Edge<ParComponent> edge = pq.get(0);
            if (edge.fromComponent() == this && edge.toComponent() == this) {
                pq.remove(0);
                continue;
            }
            return edge;
        }
        return null;
    }

    public void mergeLocked(final ParComponent other, final double edgeWeight) {
        totalWeight += other.totalWeight + edgeWeight;
        totalEdges += other.totalEdges + 1;
        final List<Edge<ParComponent>> npq = new ArrayList<>();
        int i = 0;
        int j = 0;
        while (i + j < pq.size() + other.pq.size()) {
            // get rid of inter-component edges
            while (i < pq.size()) {
                final Edge<ParComponent> e = pq.get(i);
                if ((e.fromComponent() != this && e.fromComponent() != other) || (e.toComponent() != this && e.toComponent() != other)) {
                    break;
                }
                i++;
            }
            while (j < other.pq.size()) {
                final Edge<ParComponent> e = other.pq.get(j);
                if ((e.fromComponent() != this && e.fromComponent() != other) || (e.toComponent() != this && e.toComponent() != other)) {
                    break;
                }
                j++;
            }
            if (j < other.pq.size() && (i >= pq.size() || pq.get(i).weight() > other.pq.get(j).weight())) {
                npq.add(other.pq.get(j++).replaceComponent(other, this));
            } else if (i < pq.size()) {
                npq.add(pq.get(i++).replaceComponent(other, this));
            }
        }
        other.pq.clear();
        pq.clear();
        pq = npq;
    }

    @Override
    public boolean equals(final Object o) {
        if (this == o) {
            return true;
        }
        if (!(o instanceof Component)) {
            return false;
        }

        final Component component = (Component) o;

        if (nodeId != component.nodeId()) {
            return false;
        }

        return true;
    }

    @Override
    public int hashCode() {
        return nodeId;
    }

    @Override
    public String toString() {
        return "ParComponent{" +
                "nodeId=" + nodeId +
                ", pq.size=" + pq.size() +
                ", isDead=" + isDead +
                '}';
    }
}

package edu.rice.comp322.boruvka.parallel;

import edu.rice.comp322.AbstractBoruvka;
import edu.rice.comp322.boruvka.BoruvkaFactory;
import edu.rice.comp322.boruvka.Edge;
import edu.rice.comp322.boruvka.Loader;
import edu.rice.hj.api.SuspendableException;

import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.locks.LockSupport;

/**
 * This class must be modified.
 *
 * @author <a href="http://shams.web.rice.edu/">Shams Imam</a> (shams@rice.edu)
 */
public final class ParBoruvka extends AbstractBoruvka implements BoruvkaFactory<ParComponent, ParEdge> {

    protected final Queue<ParComponent> nodesLoaded = new LinkedList<>();
    private final List<ParComponent> allComponents = new ArrayList<>();

    public ParBoruvka() {
        super();
    }

    @Override
    public boolean usesHjLib() {
        return true;
    }

    @Override
    public void initialize(final String[] args) {
        Loader.parseArgs(args);
    }

    @Override
    public void preIteration(final int iterationIndex) {
        // Exclude reading file input from timing measurement
        nodesLoaded.clear();
        Loader.read(this, nodesLoaded);
        allComponents.clear();
        allComponents.addAll(nodesLoaded);

        totalEdges = 0;
        totalWeight = 0;
    }

    @Override
    public void runIteration(int nthreads) throws SuspendableException {
        computeBoruvka(nodesLoaded, nthreads);
    }

    private void computeBoruvka(final Queue<ParComponent> nodesLoaded, final int nthreads) {
        final ConcurrentLinkedQueue<ParComponent> workQueue = new ConcurrentLinkedQueue<>(nodesLoaded);
        final AtomicInteger activeWorkers = new AtomicInteger(0);
        final int workers = Math.max(1, Math.min(nthreads, workQueue.size()));
        final Thread[] threads = new Thread[workers];

        for (int i = 0; i < workers; i++) {
            threads[i] = new Thread(() -> runWorker(workQueue, activeWorkers));
            threads[i].start();
        }

        for (final Thread thread : threads) {
            try {
                thread.join();
            } catch (final InterruptedException ie) {
                Thread.currentThread().interrupt();
                throw new RuntimeException(ie);
            }
        }

        for (final ParComponent component : allComponents) {
            if (!component.isDead) {
                totalEdges = component.totalEdges();
                totalWeight = component.totalWeight();
                return;
            }
        }
    }

    private void runWorker(final ConcurrentLinkedQueue<ParComponent> workQueue, final AtomicInteger activeWorkers) {
        while (true) {
            final ParComponent component = workQueue.poll();
            if (component == null) {
                if (activeWorkers.get() == 0 && workQueue.isEmpty()) {
                    return;
                }
                LockSupport.parkNanos(1_000_000L);
                continue;
            }

            activeWorkers.incrementAndGet();
            try {
                processComponent(component, workQueue);
            } finally {
                activeWorkers.decrementAndGet();
            }
        }
    }

    private void processComponent(final ParComponent component, final ConcurrentLinkedQueue<ParComponent> workQueue) {
        while (!component.isDead) {
            final Edge<ParComponent> edge = component.getMinEdge();
            if (edge == null) {
                return;
            }

            final ParComponent other = edge.getOther(component);
            if (other == null || other == component || other.isDead) {
                continue;
            }

            final ParComponent first = component.nodeId() <= other.nodeId() ? component : other;
            final ParComponent second = first == component ? other : component;

            first.lock();
            second.lock();
            try {
                if (component.isDead || other.isDead) {
                    continue;
                }

                final Edge<ParComponent> minEdge = component.getMinEdgeLocked();
                if (minEdge == null) {
                    return;
                }

                final ParComponent minOther = minEdge.getOther(component);
                if (minOther != other) {
                    continue;
                }

                other.isDead = true;
                component.mergeLocked(other, minEdge.weight());
                workQueue.add(component);
                return;
            } finally {
                second.unlock();
                first.unlock();
            }
        }
    }

    @Override
    public ParComponent newComponent(final int nodeId) {
        return new ParComponent(nodeId);
    }

    @Override
    public ParEdge newEdge(final ParComponent from, final ParComponent to, final double weight) {
        return new ParEdge(from, to, weight);
    }
}

package edu.rice.comp322.boruvka.parallel;

import edu.rice.comp322.boruvka.Edge;

/**
 * This class may be modified.
 *
 * @author <a href="http://shams.web.rice.edu/">Shams Imam</a> (shams@rice.edu)
 */
public final class ParEdge extends Edge<ParComponent> implements Comparable<Edge> {

    protected volatile ParComponent fromComponent;
    protected volatile ParComponent toComponent;
    public final double weight;

    protected ParEdge(final ParComponent from, final ParComponent to, final double w) {
        fromComponent = from;
        toComponent = to;
        weight = w;
    }

    @Override
    public ParComponent fromComponent() {
        return fromComponent;
    }

    @Override
    public ParComponent toComponent() {
        return toComponent;
    }

    @Override
    public double weight() {
        return weight;
    }

    /**
     * Given one member of this edge, return the other.
     */
    public ParComponent getOther(final ParComponent from) {
        if (fromComponent == from) {
            assert (toComponent != from);
            return toComponent;
        }

        if (toComponent == from) {
            assert (fromComponent != from);
            return fromComponent;
        }
        assert (false);
        return null;

    }

    @Override
    public int compareTo(final Edge e) {
        if (e.weight() == weight) {
            return 0;
        } else if (weight < e.weight()) {
            return -1;
        } else {
            return 1;
        }
    }

    /**
     * Given one member of this edge, swap it out for a different component.
     */
    public ParEdge replaceComponent(final ParComponent from, final ParComponent to) {
        if (fromComponent == from) {
            fromComponent = to;
        }
        if (toComponent == from) {
            toComponent = to;
        }
        return this;
    }
}

package edu.rice.comp322;

import edu.rice.comp322.boruvka.parallel.ParBoruvka;
import edu.rice.comp322.boruvka.sequential.SeqBoruvka;
import junit.framework.TestCase;

import java.io.IOException;
import java.io.OutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.zip.GZIPOutputStream;

import static edu.rice.hj.Module0.launchHabaneroApp;

public final class AgentBoruvkaSmallGraphTest extends TestCase {

    public void testSmallCustomGraphMatchesSequential() throws Exception {
        final Path graphFile = Files.createTempFile("boruvka-small-", ".gr.gz");
        try {
            writeGraph(graphFile);

            final AbstractBoruvka seq = new SeqBoruvka();
            final AbstractBoruvka par = new ParBoruvka();
            final String[] args = {"-iter", "1", "-f", graphFile.toString()};

            runBenchmark(seq, args, 1);
            runBenchmark(par, args, 4);

            assertEquals(seq.totalEdges(), par.totalEdges());
            assertEquals(seq.totalWeight(), par.totalWeight());
            assertEquals(3L, par.totalEdges());
            assertEquals(4.0, par.totalWeight());
        } finally {
            Files.deleteIfExists(graphFile);
        }
    }

    private void runBenchmark(final AbstractBoruvka benchmark, final String[] args, final int nthreads)
            throws IOException {
        benchmark.initialize(args);
        benchmark.preIteration(0);
        launchHabaneroApp(() -> benchmark.runIteration(nthreads));
    }

    private void writeGraph(final Path graphFile) throws IOException {
        final String graph = String.join("\n",
                "a 1 2 1",
                "a 2 3 2",
                "a 1 3 4",
                "a 3 4 1",
                "a 2 4 3") + "\n";

        try (OutputStream fileOut = Files.newOutputStream(graphFile);
             GZIPOutputStream gzipOut = new GZIPOutputStream(fileOut)) {
            gzipOut.write(graph.getBytes(StandardCharsets.UTF_8));
        }
    }
}

